        name: 'Weather.h',
        content:
          '#ifndef _WEATHER_h\n#define _WEATHER_h\n\n#include <DHT.h>\n\n#define DHTPIN 15     // Pin de datos del sensor DHT11\n#define DHTTYPE DHT11 // Tipo de sensor DHT (puedes cambiar a DHT22 si es necesario)\n#define SUN  0\n#define SUN_CLOUD  1\n#define CLOUD 2\n#define RAIN 3\n#define THUNDER 4\nDHT dht(DHTPIN, DHTTYPE);\n\nvoid initDht()\n{\n    dht.begin();\n}\n\n\n\nvoid drawWeatherSymbol(u8g2_uint_t x, u8g2_uint_t y, uint8_t symbol)\n{\n    // fonts used:\n    // u8g2_font_open_iconic_embedded_6x_t\n    // u8g2_font_open_iconic_weather_6x_t\n    // encoding values, see: https://github.com/olikraus/u8g2/wiki/fntgrpiconic\n\n    switch (symbol)\n    {\n    case SUN:\n        u8g2.setFont(u8g2_font_open_iconic_weather_6x_t);\n        u8g2.drawGlyph(x, y, 69);\n        break;\n    case SUN_CLOUD:\n        u8g2.setFont(u8g2_font_open_iconic_weather_6x_t);\n        u8g2.drawGlyph(x, y, 65);\n        break;\n    case CLOUD:\n        u8g2.setFont(u8g2_font_open_iconic_weather_6x_t);\n        u8g2.drawGlyph(x, y, 64);\n        break;\n    case RAIN:\n        u8g2.setFont(u8g2_font_open_iconic_weather_6x_t);\n        u8g2.drawGlyph(x, y, 67);\n        break;\n    case THUNDER:\n        u8g2.setFont(u8g2_font_open_iconic_embedded_6x_t);\n        u8g2.drawGlyph(x, y, 67);\n        break;\n    }\n}\nvoid drawWeather(uint8_t symbol, int degree)\n{\n    drawWeatherSymbol(0, 48, symbol);\n    u8g2.setFont(u8g2_font_logisoso32_tf);\n    u8g2.setCursor(48 + 3, 42);\n    u8g2.print(degree);\n    u8g2.print(" C"); // requires enableUTF8Print()\n  \n}\n/*\n  Draw a string with specified pixel offset.\n  The offset can be negative.\n  Limitation: The monochrome font with 8 pixel per glyph\n*/\nvoid drawScrollString(int16_t offset, const char *s)\n{\n    static char buf[36]; // should for screen with up to 256 pixel width\n    size_t len;\n    size_t char_offset = 0;\n    u8g2_uint_t dx = 0;\n    size_t visible = 0;\n    len = strlen(s);\n    if (offset < 0)\n    {\n        char_offset = (-offset) / 8;\n        dx = offset + char_offset * 8;\n        if (char_offset >= u8g2.getDisplayWidth() / 8)\n            return;\n        visible = u8g2.getDisplayWidth() / 8 - char_offset + 1;\n        strncpy(buf, s, visible);\n        buf[visible] = \'\\0\';\n        u8g2.setFont(u8g2_font_8x13_mf);\n        u8g2.drawStr(char_offset * 8 - dx, 62, buf);\n    }\n    else\n    {\n        char_offset = offset / 8;\n        if (char_offset >= len)\n            return; // nothing visible\n        dx = offset - char_offset * 8;\n        visible = len - char_offset;\n        if (visible > u8g2.getDisplayWidth() / 8 + 1)\n            visible = u8g2.getDisplayWidth() / 8 + 1;\n        strncpy(buf, s + char_offset, visible);\n        buf[visible] = \'\\0\';\n        u8g2.setFont(u8g2_font_8x13_mf);\n        u8g2.drawStr(-dx, 62, buf);\n    }\n}\nvoid draw(const char *s, uint8_t symbol, int degree)\n{\n    int16_t offset = -(int16_t)u8g2.getDisplayWidth();\n    int16_t len = strlen(s);\n    for (;;)\n    {\n        u8g2.firstPage();\n        do\n        {\n            drawWeather(symbol, degree);\n            drawScrollString(offset, s);\n        } while (u8g2.nextPage());\n        delay(20);\n        offset += 2;\n        if (offset > len * 8 + 1)\n            break;\n    }\n}\n\n\nvoid updateWEATHER() {\n    float humidity = dht.readHumidity();\n    float temperature = dht.readTemperature();\n\n    char scrollText[15];\n    sprintf(scrollText, "Humidity:%3d%%",(int)humidity);\n\n    if (temperature >= 25 && humidity >= 70) {\n        draw(scrollText, THUNDER,temperature);\n    } else if (temperature >= 20 && humidity >= 60) {\n        draw(scrollText, RAIN,temperature);\n    } else if (temperature >= 15 && humidity >= 50) {\n        draw(scrollText, RAIN, temperature);\n    } else if (temperature >= 10 && humidity >= 40) {\n        draw(scrollText, SUN_CLOUD,temperature);\n    } else if (temperature < 10 && humidity < 40) {\n        draw(scrollText, CLOUD, temperature);\n    } else {\n        draw(scrollText, SUN, temperature);\n    }\n}\n\n#endif\n',
