          '#ifndef _SOUND_h\n#define _SOUND_h\n\n/***************************************************\n  Project R2D2 Sound Generator\n\n  To all fans of StarWars and Arduino!\n\n  Written by Marcelo Larios\n\n  BSD license, all text above must be included in any redistribution\n\n  Participated in the Instructable Arduino Contest 2019\n  https://www.instructables.com/R2D2-Sound-Generator/\n****************************************************/\n\n\n#define speakerPin 2\nint freq = 2000;\nint channel = 0;\nint resolution = 8;\n\n\n#define  C0 16.35\n#define Db0 17.32\n#define D0  18.35\n#define Eb0 19.45\n#define E0  20.60\n#define F0  21.83\n#define Gb0 23.12\n#define G0  24.50\n#define Ab0 25.96\n#define LA0 27.50\n#define Bb0 29.14\n#define B0  30.87\n#define C1  32.70\n#define Db1 34.65\n#define D1  36.71\n#define Eb1 38.89\n#define E1  41.20\n#define F1  43.65\n#define Gb1 46.25\n#define G1  49.00\n#define Ab1 51.91\n#define LA1 55.00\n#define Bb1 58.27\n#define B1  61.74\n#define C2  65.41\n#define Db2 69.30\n#define D2  73.42\n#define Eb2 77.78\n#define E2  82.41\n#define F2  87.31\n#define Gb2 92.50\n#define G2  98.00\n#define Ab2 103.83\n#define LA2 110.00\n#define Bb2 116.54\n#define B2  123.47\n#define C3  130.81\n#define Db3 138.59\n#define D3  146.83\n#define Eb3 155.56\n#define E3  164.81\n#define F3  174.61\n#define Gb3 185.00\n#define G3  196.00\n#define Ab3 207.65\n#define LA3 220.00\n#define Bb3 233.08\n#define B3  246.94\n#define C4  261.63\n#define Db4 277.18\n#define D4  293.66\n#define Eb4 311.13\n#define E4  329.63\n#define F4  349.23\n#define Gb4 369.99\n#define G4  392.00\n#define Ab4 415.30\n#define LA4 440.00\n#define Bb4 466.16\n#define B4  493.88\n#define C5  523.25\n#define Db5 554.37\n#define D5  587.33\n#define Eb5 622.25\n#define E5  659.26\n#define F5  698.46\n#define Gb5 739.99\n#define G5  783.99\n#define Ab5 830.61\n#define LA5 880.00\n#define Bb5 932.33\n#define B5  987.77\n#define C6  1046.50\n#define Db6 1108.73\n#define D6  1174.66\n#define Eb6 1244.51\n#define E6  1318.51\n#define F6  1396.91\n#define Gb6 1479.98\n#define G6  1567.98\n#define Ab6 1661.22\n#define LA6 1760.00\n#define Bb6 1864.66\n#define B6  1975.53\n#define C7  2093.00\n#define Db7 2217.46\n#define D7  2349.32\n#define Eb7 2489.02\n#define E7  2637.02\n#define F7  2793.83\n#define Gb7 2959.96\n#define G7  3135.96\n#define Ab7 3322.44\n#define LA7 3520.01\n#define Bb7 3729.31\n#define B7  3951.07\n#define C8  4186.01\n#define Db8 4434.92\n#define D8  4698.64\n#define Eb8 4978.03\n// DURATION OF THE NOTES \n#define BPM 120 //  you can change this value changing all the others\n// I think tecnically BPM supposed to be 104, but original 120\n// from instructable sounds good.  180 sounds speedy, 240 sounds mario, 300 sounds\n// middle eastern, 400 middle eastern techno pop?\n#define H 2*Q //half 2/4\n#define Q 60000/BPM //quarter 1/4 \n#define E Q/2   //eighth 1/8\n#define S Q/4 // sixteenth 1/16\n#define W 4*Q // whole 4/4\n\n\n\nvoid phrase1()\n{\n    int k = random(1000, 2000);\n    for (int i = 0; i <= random(100, 2000); i++)\n    {\n        tone(speakerPin, k + (-i * 2));\n        vTaskDelay(pdMS_TO_TICKS((random(.9, 2))));\n    }\n    for (int i = 0; i <= random(100, 1000); i++)\n    {\n        tone(speakerPin, k + (i * 10));\n        vTaskDelay(pdMS_TO_TICKS((random(.9, 2))));\n    }\n}\n\nvoid phrase2()\n{\n\n    int k = random(1000, 2000);\n    for (int i = 0; i <= random(100, 2000); i++)\n    {\n        tone(speakerPin, k + (i * 2));\n        vTaskDelay(pdMS_TO_TICKS((random(.9, 2))));\n    }\n    for (int i = 0; i <= random(100, 1000); i++)\n    {\n        tone(speakerPin, k + (-i * 10));\n        vTaskDelay(pdMS_TO_TICKS((random(.9, 2))));\n    }\n}\n\nvoid playerTone()\n{\n    int K = 2000;\n    switch (random(1, 7))\n    {\n    case 1:\n        phrase1();\n        break;\n    case 2:\n        phrase2();\n        break;\n    case 3:\n        phrase1();\n        phrase2();\n        break;\n    case 4:\n        phrase1();\n        phrase2();\n        phrase1();\n        break;\n    case 5:\n        phrase1();\n        phrase2();\n        phrase1();\n        phrase2();\n        phrase1();\n        break;\n    case 6:\n        phrase2();\n        phrase1();\n        phrase2();\n        break;\n    }\n    for (int i = 0; i <= random(3, 9); i++)\n    {\n        tone(speakerPin, K + random(-1700, 2000));\n        vTaskDelay(pdMS_TO_TICKS((random(70, 170))));\n        noTone(speakerPin);\n        vTaskDelay(pdMS_TO_TICKS((random(0, 30))));\n    }\n    noTone(speakerPin);\n    vTaskDelay(pdMS_TO_TICKS((random(2000, 4000))));\n}\n\n\n\nvoid mytone(int freq, int duration) {\n  ledcWriteTone(channel, freq);\n  vTaskDelay(pdMS_TO_TICKS((duration)));\n  ledcWriteTone(channel, 0);\n}\n \nvoid StarWars() { \n  ledcSetup(channel, freq, resolution);\n  ledcAttachPin(speakerPin, channel);\n }\n \nvoid StarWarsPlay() {\n  //mytone(note, duration)\n    mytone(LA3,Q); \n    mytone(LA3,Q);\n    mytone(LA3,Q);\n    mytone(F3,E+S);\n    mytone(C4,S);\n    \n    mytone(LA3,Q);\n    mytone(F3,E+S);\n    mytone(C4,S);\n    mytone(LA3,H);\n    \n    mytone(E4,Q); \n    mytone(E4,Q);\n    mytone(E4,Q);\n    mytone(F4,E+S);\n    mytone(C4,S);\n    \n    mytone(Ab3,Q);\n    mytone(F3,E+S);\n    mytone(C4,S);\n    mytone(LA3,H);\n    \n    mytone(LA4,Q);\n    mytone(LA3,E+S);\n    mytone(LA3,S);\n    mytone(LA4,Q);\n    mytone(Ab4,E+S);\n    mytone(G4,S);\n    \n    mytone(Gb4,S);\n    mytone(E4,S);\n    mytone(F4,E);\n    vTaskDelay(pdMS_TO_TICKS((E)));//PAUSE\n    mytone(Bb3,E);\n    mytone(Eb4,Q);\n    mytone(D4,E+S);\n    mytone(Db4,S);\n    \n    mytone(C4,S);\n    mytone(B3,S);\n    mytone(C4,E);\n    vTaskDelay(pdMS_TO_TICKS((E)));//PAUSE QUASI FINE RIGA\n    mytone(F3,E);\n    mytone(Ab3,Q);\n    mytone(F3,E+S);\n    mytone(LA3,S);\n  \n    mytone(C4,Q);\n    mytone(LA3,E+S);\n    mytone(C4,S);\n    mytone(E4,H);\n    \n    mytone(LA4,Q);\n    mytone(LA3,E+S);\n    mytone(LA3,S);\n    mytone(LA4,Q);\n    mytone(Ab4,E+S);\n    mytone(G4,S);\n    \n    mytone(Gb4,S);\n    mytone(E4,S);\n    mytone(F4,E);\n    vTaskDelay(pdMS_TO_TICKS((E)));//PAUSE\n    mytone(Bb3,E);\n    mytone(Eb4,Q);\n    mytone(D4,E+S);\n    mytone(Db4,S);\n    \n    mytone(C4,S);\n    mytone(B3,S);\n    mytone(C4,E);\n    vTaskDelay(pdMS_TO_TICKS((E)));//PAUSE QUASI FINE RIGA\n    mytone(F3,E);\n    mytone(Ab3,Q);\n    mytone(F3,E+S);\n    mytone(C4,S);\n    \n    mytone(LA3,Q);\n    mytone(F3,E+S);\n    mytone(C4,S);\n    mytone(LA3,H);\n    \n    vTaskDelay(pdMS_TO_TICKS((2*H)));\n}\n\nvoid vSoundTask(void *pvParameters)\n{\n    while (1)\n    {\n        playerTone();\n        vTaskDelay(pdMS_TO_TICKS(random(60000, 600000)));\n    }\n}\n\n\n#endif',
